pt.code:
// Armazenar um item
localStorage.setItem('nomeUsuario', 'João Silva');

// Recuperar um item
let usuario = localStorage.getItem('nomeUsuario');
console.log(usuario); // Saída: João Silva

// Remover um item
localStorage.removeItem('nomeUsuario');

// Limpar todo o localStorage (use com cuidado!)
// localStorage.clear();

